/** Union of every Aura token name (camelCase). */
export type AuraTokenName = keyof typeof auraTokens;

/** Union of every concrete Aura token value string. */
export type AuraTokenValue = (typeof auraTokens)[AuraTokenName];

/**
 * Companion to `auraTokens`: same keys, values are `var(--aura-*)` references.
 * Use these in inline styles so the value stays live when a named theme is active.
 *
 * @example
 * ```tsx
 * import { auraTokenVars } from "@aura-design/core/tokens";
 *
 * // value stays current when the user switches to "warm-dusk" or any named theme:
 * <div style={{ background: auraTokenVars.bg2, color: auraTokenVars.text }} />
 * ```
 */
export declare const auraTokenVars: Readonly<Record<AuraTokenName, string>>;
